const server = http.createServer((req, res) => {
    // CORS and security headers
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('X-Frame-Options', 'DENY');
    res.setHeader('Content-Security-Policy', "default-src 'self'; script-src 'unsafe-inline'; style-src 'unsafe-inline'");

    const url = new URL(req.url, `http://${req.headers.host}`);

    if (req.method === 'GET' && url.pathname === '/') {
        res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
        res.end(HTML_CONTENT);
        return;
    }

    if (req.method === 'POST' && url.pathname === '/api/join') {
        let body = '';
        let bodySize = 0;
        const MAX_BODY = 1024;

        req.on('data', chunk => {
            bodySize += chunk.length;
            if (bodySize > MAX_BODY) {
                res.writeHead(413);
                res.end('{"error":"payload too large"}');
                req.destroy();
                return;
            }
            body += chunk;
        });

        req.on('end', () => {
            try {
                const data = JSON.parse(body);
                const result = gameServer.createPlayer(data.name);
                if (!result) {
                    res.writeHead(400, { 'Content-Type': 'application/json' });
                    res.end(JSON.stringify({ error: 'Invalid name' }));
                    return;
                }
                res.writeHead(200, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify(result));
            } catch (e) {
                res.writeHead(400, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify({ error: 'Invalid request' }));
            }
        });
        return;
    }

    if (req.method === 'POST' && url.pathname === '/api/input') {
        // SECURE: Authenticate via session token
        const authHeader = req.headers['authorization'] || '';
        const token = authHeader.replace('Bearer ', '');
        const player = gameServer.authenticateRequest(token);

        if (!player) {
            res.writeHead(401, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ error: 'Unauthorized' }));
            return;
        }

        let body = '';
        let bodySize = 0;
        const MAX_BODY = 512;

        req.on('data', chunk => {
            bodySize += chunk.length;
            if (bodySize > MAX_BODY) {
                res.writeHead(413);
                res.end('{"error":"payload too large"}');
                req.destroy();
                return;
            }
            body += chunk;
        });

        req.on('end', () => {
            try {
                const input = JSON.parse(body);
                // SECURE: Server validates and processes input
                // Server does NOT use any client-reported delta time
                const result = gameServer.processInput(player, input);
                res.writeHead(200, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify(result));
            } catch (e) {
                res.writeHead(400, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify({ error: 'Invalid input' }));
            }
        });
        return;
    }

    if (req.method === 'GET' && url.pathname === '/api/state') {
        const authHeader = req.headers['authorization'] || '';
        const token = authHeader.replace('Bearer ', '');
        const player = gameServer.authenticateRequest(token);

        if (!player) {
            res.writeHead(401, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ error: 'Unauthorized' }));
            return;
        }

        const state = gameServer.getGameState(player);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(state));
        return;
    }

    res.writeHead(404);
    res.end('Not found');
});

